import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {'3': {'1': '<p>YHWH of hosts (<em>adonai YHWH tsvaot</em>) strips Jerusalem of every support — the removal of food, water, warrior, judge, prophet, elder. This is the covenant reversal of Deut 28:43-44: instead of being the head, Israel becomes leaderless and chaotic. The removal of prophets and diviners together suggests YHWH is withdrawing the mediating channels through which his word came — the vacuum will be filled by chaos (v 4). In the NT pattern, the removal of legitimate authority structures (judge, prophet, counselor) prefigures the scattering of the disciples (Zech 13:7, Matt 26:31) and the spiritual desolation that falls on those who reject the true Shepherd (John 10:10-13).</p>', '2': '<p>The warrior, soldier, judge, and prophet form the four pillars of a stable society — military, legal, judicial, and revelatory authority. Their removal signals total institutional collapse. In the prophetic trajectory, the failure of human judges and warriors points to the need for the one judge and warrior in whom all these roles are permanently held: the servant-king who is judge (Isa 11:3-4), warrior (63:1-6), prophet (61:1), and shepherd (40:11).</p>', '3': "<p>Even the captain of fifty (a minor military officer), the skilled artisan, and the expert enchanter are removed — YHWH's judgment reaches every level of society, leaving no competent leadership. The skilled artisan (<em>harash</em>) will reappear in 40:19-20 and 44:9-20 as the maker of idols — here the point is that even technical skill and social competence are covenant gifts that YHWH can withdraw. The vacuum of true leadership is ultimately answered by the Servant who is both craftsman of salvation and judge of the earth.</p>", '4': '<p>Youths and infants rule — the ultimate indignity in an honor-culture where age and wisdom were synonymous. This is not commentary on youth but on social inversion as judgment: when YHWH removes his blessing, the structures that sustain mature governance collapse. The opposite of this judgment is the child who will bear the government on his shoulder (9:6) — the Davidic child-king who governs not from human wisdom but from the Spirit of counsel (11:2).</p>', '5': "<p>Social breakdown: neighbor against neighbor, youth against age, worthless person against honorable. The social fabric tears precisely because the fear of YHWH that held it together is gone. The NT applies this inversion pattern to the end-times (2 Tim 3:1-5, Mark 13:12) — the collapse of social order is a mark of the time before the Son of Man's coming. In the Christological framework: judgment through social chaos is the negative image of the kingdom where the wolf and lamb live together (65:25, 11:6).</p>", '6': "<p>The desperate grab for leadership — a man is seized and told to lead simply because he has a robe — shows that the crisis of authority is so acute that anyone with any resource is pressed into service. The condition he inherits is called a <em>mekhshelah</em> (stumbling-heap, ruin). This images the disciples' flight at Jesus' arrest — when the Shepherd is struck, the sheep scatter and will seize any cover available (Mark 14:50). The true leader who does not flee from the ruin is the Servant who takes the heap of our iniquity upon himself (53:6).</p>", '7': '<p>The seized man protests: I am no healer; in my house there is no bread and no robe — he refuses to be made leader of the people because he has nothing to give. The refusal of unqualified leadership is ironically correct: no human leader can heal what ails Jerusalem. Only the Servant who takes on our wounds can heal (53:4-5). The healer-who-is-not-a-healer points negatively to the one who is the true physician — Jesus who came not for the healthy but for the sick (Mark 2:17).</p>', '8': '<p>Jerusalem has stumbled and Judah has fallen — the formal charge. In word and deed they rebelled against YHWH, defying his glorious presence (<em>kavod</em>). The rebellion against the <em>kavod</em> (glory) of YHWH is the deepest covenant offense: it is the glory that filled the temple (6:3) and that the Servant will bring to the nations (42:8, 49:3). The fall of Jerusalem that their sin causes is answered by the exaltation of the Servant (52:13) — the one through whom the glory returns (40:5: all flesh shall see it together).</p>', '9': '<p>They flaunt their sin like Sodom and do not conceal it. Woe to them — they have brought disaster on themselves. The Sodom comparison is the most severe in the prophetic tradition: it marks Jerusalem as comparable to the city destroyed by divine fire for public, unrepentant wickedness. Jesus applies the Sodom comparison to the cities that reject his messengers (Matt 10:15, 11:23-24), intensifying the judgment on covenant-community rejection: it will be more bearable for Sodom on that day than for those who reject the Son.</p>', '10': '<p>Tell the righteous it will go well for them — they will enjoy the fruit of their actions. This promise to the righteous within the corrupt community is a seed of the doctrine of the faithful remnant (1:9, 6:13, 10:20-22). In the NT, the righteous who endure are those who cling to the word when the false prophets and leaders have failed. The fruit-of-their-actions principle reflects the Christological pattern: the Servant who does right bears fruit (53:10 — he will see offspring), while the wicked bear the fruit of their wickedness (v 11).</p>', '11': "<p>Woe to the wicked — what their hands have done will be done to them in return. The lex talionis of covenant judgment: the measure given is the measure received (Luke 6:38). In Christological perspective: the wicked who crush the poor (v 15) and strip the vineyard (v 14) are precisely those who will be stripped in turn (vv 18-24). The one exception to this retributive pattern is the Servant, who bears the return of others' wickedness upon himself (53:5-6) — breaking the cycle of woe by absorbing it.</p>", '12': "<p>My people — your oppressors are children, women rule over you; your guides mislead you and confuse the direction of your paths. The confusion of paths (<em>derekh</em>) is the covenant catastrophe: YHWH's way was clear (2:3, the law going out from Zion), but false guides have subverted it. Jesus will describe himself as the Way (John 14:6) — the true guide who does not mislead — in deliberate contrast to false shepherds and guides who scatter and confuse (Matt 15:14, John 10:8).</p>", '13': '<p>YHWH has taken his stand to bring a charge (<em>riv</em>) — the covenant lawsuit form. He stands to render judgment on the peoples. The divine standing-to-judge is the theophanic posture of the heavenly court (Ps 82:1). In the NT, this standing judgment-posture transfers to the Son of Man standing at the right hand of God to receive Stephen (Acts 7:55-56) and to the final judgment throne (Matt 25:31-32). The one who here stands as plaintiff becomes the one before whom all nations stand at the last day.</p>', '14': '<p>YHWH brings his case against the elders and leaders: You have plundered the vineyard; the goods stolen from the poor are in your houses. The vineyard is Israel (5:1-7); its plundering by the leaders is a charge that will recur in the parable of the wicked tenants (Matt 21:33-41), where Jesus directly quotes Isa 5:1-2 and identifies the leaders of Israel as the tenants who have stolen what belongs to the vineyard owner. The connection between this judgment and the cross is explicit: the tenants kill the Son to seize the inheritance.</p>', '15': "<p>What do you think you are doing, crushing my people and grinding the faces of the poor into the dust? — declares the Lord GOD of hosts. The crushing of the poor is the form the Sodom-sin takes in this covenant community: not sexual violence but economic oppression. The face-grinding image is extreme — the poor are literally pressed into the dust. Jesus' inaugural sermon in Nazareth (Luke 4:18, quoting Isa 61:1) announces good news to the poor as the specific reversal of this grinding — the Servant comes to lift from the dust those who have been pressed into it.</p>", '16': "<p>The daughters of Zion are proud — heads held high, seductive glances, prancing steps, jingle of anklets. The pride of Zion's women is not incidental but symptomatic: a society that is exploiting the poor (v 14-15) while its elite adorn themselves with luxury is spiritually inverted. The specific condemnation of ostentatious display recurs in 1 Tim 2:9 and 1 Pet 3:3-4 — the NT applies the Isaianic critique of outward adornment to the covenant community's ongoing temptation to confuse external status with inner righteousness.</p>", '17': "<p>The Lord will afflict their scalps with sores and expose their shame — the physical reversal of their pride. Shame replaces honor, exposure replaces concealment. The stripping of the women of Zion is the judgment that mirrors the stripping of the Servant (52:14, 53:2-3) in reverse: the Servant is stripped and shamed as a substitutionary bearing of what his people deserve; the daughters of Zion who do not accept the Servant's bearing will be stripped for their own sin.</p>", '18': '<p>In that day the Lord will remove their ornamental anklets, headbands, and crescent necklaces. The detailed inventory of vv 18-23 is a stripping catalogue — each item of adornment that signified status will be taken. Crescent necklaces were associated with moon-worship and Canaanite fertility religion; their removal signals not merely loss of fashion but loss of false-god reliance. The NT equivalent: stripping of all worldly reliance (Matt 6:19-20, Rev 3:18 — buy from me gold refined in fire) in preparation for the true adornment.</p>', '19': "<p>The earrings, bracelets, and veils — items that covered and adorned. The veil (<em>redid</em>) in the ancient world signified the distinction between the protected/married woman and the slave or prostitute. Its removal in judgment is devastating. In contrast, the NT speaks of a new veil — the veil of the temple torn at Jesus' death (Matt 27:51), opening access to God and removing the old barrier. The tearing of the Jerusalem veil is the judgment of this chapter enacted at its climax.</p>", '20': "<p>Turbans, armlets, sashes, perfume bottles, lucky charms (<em>lehashim</em> — literally serpent-charms or amulets). The lucky charms reveal the syncretism beneath the surface: the women of Jerusalem practiced apotropaic magic alongside covenant religion. Their removal is YHWH's purification of the community from dependence on anything other than himself. The false refuges of the wealthy are stripped precisely so that the true refuge — the Branch of 4:2 — can be seen.</p>", '21': "<p>Signet rings and nose rings — the signet ring was the seal of personal identity and authority (used to ratify documents). Its removal means loss of standing and agency. In contrast, the NT speaks of the Spirit given as a seal (<em>sphragis</em>, 2 Cor 1:22, Eph 1:13) — the true signet by which the people of God are marked as his own. The Servant's seal of suffering becomes the permanent identification of those who belong to YHWH.</p>", '22': "<p>Holiday garments, capes, wraps, purses — the clothing of festival celebration, of the Sabbath and the great feasts. Their removal means that the festivals themselves will be stripped of meaning: what was worn for worship will be taken. The contrast is the new garment YHWH provides: the garment of salvation (61:10), the robe of righteousness, which the Servant's work makes available for those who receive it.</p>", '23': '<p>Polished mirrors, linen tunics, tiaras, and full-length veils — the accessories of the upper-class Jerusalemite woman. The linen tunics (<em>sadinim</em>) echo the priestly linen (Exod 28:39), suggesting that even the priestly class has adopted the luxury culture being condemned. The complete stripping of vv 18-23 leaves the women of Zion with nothing — the precondition, as the narrative of chapter 4 shows, for the Branch to clothe the remnant with something that cannot be stripped (4:2).</p>', '24': "<p>Instead of sweet perfume — a stench; instead of a sash — a rope; instead of styled hair — a shaved head; instead of a fine robe — a garment of sackcloth; instead of beauty — a brand. The five reversals move from luxury to prisoner-status: the rope and shaved head are the marks of a captive taken in war; the sackcloth is mourning-garb; the brand marks a slave. Every marker of free, adorned, high-status femininity is inverted to its captive, mourning opposite. This is the shape of covenant curse — Deut 28:41 (you will have sons and daughters but you will not keep them, for they will go into captivity). The stripping anticipates the Servant's stripping (52:14), with the difference that the Servant bears the curse voluntarily while those here bear it for their own sin.</p>", '25': "<p>Your men will fall by the sword, your warriors in the heat of battle. The military disaster that will accompany the social stripping: the judgment is total — social, economic, and military. The fallen warriors of Jerusalem will be answered only by the triumphant arm of YHWH (51:5) and the warrior-Servant who goes into battle alone (63:3-6) and emerges victorious. The sword that falls on Jerusalem's men falls ultimately on the Servant (53:8 — he was cut off from the land of the living).</p>", '26': "<p>Her gates will mourn and grieve; she will sit desolate on the ground. The personification of Jerusalem's gates as mourners is the last image: the entry-points of the city (the places of commerce, judgment, and community life) are personified as grief-stricken. She sits on the ground — the posture of the deepest mourning (Lam 1:1: how lonely sits the city). The desolate woman sitting on the ground is the negative image of the restored Jerusalem of 54:1 (sing, barren woman!) and 52:2 (rise up, sit enthroned). The desolation of chapter 3 is the condition that the Branch of chapter 4 will reverse.</p>"}, '4': {'1': "<p>In that day seven women will seize one man — the demographic catastrophe after the military slaughter of 3:25. The seven-to-one ratio suggests nearly total male death. The women's plea — let us use your name, only let us take away our reproach — is a reversal of the normal marriage contract: they offer to support themselves if they can only bear a husband's name and escape social shame. The reproach (<em>herpah</em>) is the stigma of unmarried or childless status. This desolation sets the stage: the community is at its lowest before the Branch appears. The Christological pattern: the Valley of Achor (trouble) becomes a door of hope (Hos 2:15); the desolation of 4:1 becomes the occasion for the Branch of 4:2.</p>", '2': "<p>In that day the Branch of YHWH (<em>tsemach YHWH</em>) will be beautiful and glorious — the most explicit messianic title in the early chapters of Isaiah. The <em>tsemach</em> (Branch/Shoot) becomes a technical messianic term in Jer 23:5, 33:15, Zech 3:8, 6:12 — always pointing to the Davidic king who will reign in righteousness. Here <em>tsemach YHWH</em> (the Branch of YHWH himself) suggests more than a Davidic descendant: the Branch belongs to YHWH in a unique sense. The produce of the land being the pride and splendor of the survivors merges the messianic figure with the land's fruitfulness — the Davidic king and creation's restoration are inseparable. The NT identifies Jesus as the <em>tsemach</em>: the shoot from the stump of Jesse (11:1), the true vine (John 15:1), the firstfruits of the new creation (1 Cor 15:20-23).</p>", '3': "<p>Everyone who remains in Zion and is left in Jerusalem will be called holy — enrolled among the living. The remnant principle reaches its eschatological culmination: the survivors are designated <em>qadosh</em> (holy), the same term applied to YHWH's seraphim-proclaimed holiness (6:3). To be called holy is to be included in YHWH's own sphere of the sacred. The enrolled-among-the-living language anticipates the book of life (Rev 20:12-15, 21:27) — the final register of those who belong to the new Jerusalem. Peter applies the same language to the church: a holy nation (1 Pet 2:9), the eschatological community of those who remain.</p>", '4': "<p>The Lord will wash away the filth of the daughters of Zion and rinse the blood from the midst of Jerusalem by a spirit of judgment and a spirit of burning. The washing is YHWH's act, not Israel's self-purification. The spirit of judgment (<em>ruach mishpat</em>) and spirit of burning (<em>ruach baer</em>) are the two modes of the divine purification: forensic judgment that declares guilt and consuming fire that removes it. John the Baptist announces the same double purification: baptism with water and with fire and the Holy Spirit (Matt 3:11-12). The burning of the chaff and the gathering of the wheat into the barn is the Christological fulfillment of this verse — the Son comes with a winnowing fork (Matt 3:12).</p>", '5': '<p>Then YHWH will create over every dwelling-place on Mount Zion and over all her gatherings a cloud by day and smoke with the glow of flaming fire by night. The re-creation of the Sinai wilderness pillar of cloud and fire over the whole community, not just the tabernacle — the Shekinah presence that was localized in the tabernacle and temple is now extended to every household in Zion. This is the new-creation Pentecost: the Spirit-fire that rested on the single tabernacle becomes the Spirit poured out on all flesh (Joel 2:28-29, Acts 2:1-4). The tongues of fire over the assembled disciples in Acts 2:3 are the new-covenant fulfillment of this verse — the cloud and fire of divine presence descending on the whole assembly.</p>', '6': "<p>There will be a shelter for shade from the heat of the day, a refuge and hiding place from storm and rain. The shelter (<em>sukkah</em>) of the presence completes the restoration: the wilderness wandering's temporary shelter (the Feast of Sukkot) is now permanent. The shade from heat and refuge from storm echo the language of Ps 91 (he who dwells in the shelter of the Most High) and the Servant's description (32:2 — a man will be like a hiding place from the wind, a shelter from the storm). Jesus as the tabernacle dwelling of God (John 1:14, <em>eskēnōsen en hēmin</em> — pitched his tent among us) fulfills this promise: in him the shelter of God's presence is made permanent and universally accessible.</p>"}}

def main():
    data = load_comm('mkt-christ', 'isaiah')
    merge_comm(data, ISAIAH)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Isaiah christ: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-christ', 'isaiah', data)

if __name__ == '__main__':
    main()
